class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        MOD = 10**9 + 7
        res = 0
        if n == 1:
            for i in range(1, 10):
                if i % k == 0:
                    res += 1
            return res
        half = n // 2 + n % 2
        for i in range(1, 10):
            if i % k == 0:
                res += self.A(half - 1, n - half) * 9
        if n % 2 == 1:
            for i in range(10):
                if i % k == 0:
                    res += self.A(half - 1, half - 1) * 9
        return res % MOD

    def A(self, a, b):
        res = 1
        for _ in range(b):
            res *= a
            a -= 1
        return res
